"use client";

/**
 * AuctioneerSection — Bloque/sección de Concorde (Voyager DS)
 *
 * Card de subastador (766 × 352): cabecera con nombre + nº de ofertas, logo
 * central (slot) y "Ir al Perfil", sobre una fila de 4 OfferCards.
 * Compuesta 100% con componentes Concorde: OfferCard · BadgeStatus · ProfileButton.
 */

import type { JSX, ReactNode } from "react";
import OfferCard from "../../../components/OfferCard";
import BadgeStatus from "../../../components/BadgeStatus";
import ProfileButton from "../../../components/ProfileButton";
import CardTitle from "../../../components/CardTitle";

export type AuctioneerBadge = "none" | "live" | "proxima";

export interface AuctioneerOffer {
  name: string;
  year: string | number;
  price: string;
  imageSrc?: string;
  badge?: AuctioneerBadge;
}

export interface AuctioneerSectionProps {
  /** Nombre del subastador */
  name?: string;
  /** Etiqueta de ofertas (p.ej. "10 Ofertas") */
  offersLabel?: string;
  /** Logo central (slot) — por defecto un placeholder */
  logo?: ReactNode;
  /** Las 4 ofertas (cards) */
  offers?: AuctioneerOffer[];
  onProfile?: () => void;
  className?: string;
}

export const AUCTIONEER_WIDTH = 766;
export const AUCTIONEER_HEIGHT = 352;

const DEFAULT_OFFERS: AuctioneerOffer[] = [
  { name: "Audi Q3", year: 2026, price: "US$ 9,999", imageSrc: "/demo/bronco.jpg" },
  { name: "Audi Q3", year: 2026, price: "US$ 9,999", imageSrc: "/demo/bronco.jpg", badge: "live" },
  { name: "Audi Q3", year: 2026, price: "US$ 9,999", imageSrc: "/demo/bronco.jpg" },
  { name: "Audi Q3", year: 2026, price: "US$ 9,999", imageSrc: "/demo/bronco.jpg", badge: "proxima" },
];

function badgeFor(badge: AuctioneerBadge | undefined): JSX.Element | undefined {
  if (badge === "live") return <BadgeStatus variant="live" />;
  if (badge === "proxima") return <BadgeStatus variant="proxima" />;
  return undefined;
}

export default function AuctioneerSection({
  name = "SANTANDER CONSUMER",
  offersLabel = "10 Ofertas",
  logo,
  offers = DEFAULT_OFFERS,
  onProfile,
  className = "",
}: AuctioneerSectionProps): JSX.Element {
  return (
    <section
      className={className}
      style={{
        position: "relative",
        boxSizing: "border-box",
        width: AUCTIONEER_WIDTH,
        height: AUCTIONEER_HEIGHT,
        background: "#ffffff",
        borderRadius: 16,
        boxShadow: "rgba(0,0,0,0.07) 0px 0px 16px 4px",
        padding: "20px 16px 16px",
        display: "flex",
        flexDirection: "column",
        justifyContent: "space-between",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Cabecera */}
      <header style={{ position: "relative", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 8px" }}>
        {/* Izquierda: CardTitle (nombre + ofertas + corchetes naranjas) */}
        <CardTitle title={name} subtitle={offersLabel} titleSize={16} subtitleSize={14} />

        {/* Centro: logo (slot opcional) */}
        {logo ? <div style={{ position: "absolute", top: 0, left: "50%", transform: "translateX(-50%)" }}>{logo}</div> : null}

        {/* Derecha: Ir al Perfil */}
        <ProfileButton onClick={onProfile}>Ir al Perfil</ProfileButton>
      </header>

      {/* Fila de ofertas */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
        {offers.map(function renderOffer(o, i) {
          return (
            <OfferCard
              key={i}
              variant="live"
              name={o.name}
              year={o.year}
              price={o.price}
              imageSrc={o.imageSrc}
              badge={badgeFor(o.badge)}
              elevated
            />
          );
        })}
      </div>
    </section>
  );
}

"use client";

/**
 * CategoriesSection — Bloque/sección de Concorde (Voyager DS)
 *
 * Card de 2 columnas (766 × 184):
 *   · Izquierda  "TIPO DE OFERTA"  → 2 OfferType (NEGOCIABLE · EN VIVO)
 *   · Derecha    "CATEGORÍAS"      → 4 CategoryCard
 * Separadas por un divisor vertical. Compuesta 100% con componentes Concorde:
 * CardTitle · OfferType · CategoryCard.
 */

import type { JSX } from "react";
import CardTitle from "../../../components/CardTitle";
import OfferType from "../../../components/OfferType";
import CategoryCard from "../../../components/CategoryCard";

export const CATEGORIES_WIDTH = 766;
export const CATEGORIES_HEIGHT = 184;

export interface CategoriesSectionProps {
  onNegotiable?: () => void;
  onLive?: () => void;
  onCategory?: (category: string) => void;
  className?: string;
}

const colStyle = { display: "flex", flexDirection: "column" as const, alignItems: "flex-start" as const, justifyContent: "space-between" as const, height: 143, gap: 8 };

export default function CategoriesSection({
  onNegotiable,
  onLive,
  onCategory,
  className = "",
}: CategoriesSectionProps): JSX.Element {
  return (
    <section
      className={className}
      style={{
        boxSizing: "border-box",
        width: CATEGORIES_WIDTH,
        height: CATEGORIES_HEIGHT,
        background: "#ffffff",
        borderRadius: 16,
        boxShadow: "rgba(0,0,0,0.07) 0px 0px 16px 4px",
        padding: "12px 20px",
        display: "flex",
        alignItems: "center",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Columna izquierda: TIPO DE OFERTA */}
      <div style={{ ...colStyle, paddingRight: 24 }}>
        <CardTitle title="TIPO DE OFERTA" subtitle="" />
        <div style={{ display: "flex", gap: 12 }}>
          <OfferType variant="negotiable" onClick={onNegotiable} />
          <OfferType variant="live" onClick={onLive} />
        </div>
      </div>

      {/* Divisor vertical */}
      <div style={{ width: 1, height: 143, background: "#E5E7EB" }} />

      {/* Columna derecha: CATEGORÍAS */}
      <div style={{ ...colStyle, flex: 1, paddingLeft: 24 }}>
        <CardTitle title="CATEGORÍAS" subtitle="" />
        <div style={{ display: "flex", gap: 12, justifyContent: "space-between", width: "100%" }}>
          <CategoryCard category="vehicular" onClick={onCategory ? function h() { onCategory("vehicular"); } : undefined} />
          <CategoryCard category="maquinaria" onClick={onCategory ? function h() { onCategory("maquinaria"); } : undefined} />
          <CategoryCard category="equipos-diversos" onClick={onCategory ? function h() { onCategory("equipos-diversos"); } : undefined} />
          <CategoryCard category="articulos-diversos" onClick={onCategory ? function h() { onCategory("articulos-diversos"); } : undefined} />
        </div>
      </div>
    </section>
  );
}

/**
 * Dimensiones del bloque Homepage (desktop) — módulo plano sin "use client".
 * Los Server Components y los Viewers pueden importar estas constantes
 * sin cruzar la barrera "use client" → undefined → NaN.
 */

export const HOMEPAGE_WIDTH = 798;
export const HOMEPAGE_HEIGHT = 1104;

/**
 * Homepage — Bloque de Concorde (Voyager DS)
 *
 * Bloque = composición de varios componentes. Por ahora es solo el lienzo
 * base: un fondo blanco de 798 × 1104. Iremos montando las secciones encima.
 */

import type { JSX } from "react";
import AuctioneerSection from "./AuctioneerSection";
import CategoriesSection from "./CategoriesSection";

export interface HomepageProps {
  className?: string;
}

import { HOMEPAGE_WIDTH, HOMEPAGE_HEIGHT } from "./dimensions";
export { HOMEPAGE_WIDTH, HOMEPAGE_HEIGHT } from "./dimensions";

export default function Homepage({ className = "" }: HomepageProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="homepage"
      style={{
        position: "relative",
        width: HOMEPAGE_WIDTH,
        height: HOMEPAGE_HEIGHT,
        background: "#ffffff",
        overflow: "hidden",
      }}
    >
      {/* Principal Banner 766 × 272 · 16px arriba del Secondary, centrado */}
      <div
        data-slot="principal-banner"
        style={{
          position: "absolute", left: "50%", bottom: 816, transform: "translateX(-50%)",
          width: 766, height: 272, borderRadius: 8, background: "#E9EAEC",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
          fontSize: 13, fontWeight: 600, letterSpacing: "0.06em", color: "#9AA1AC",
        }}
      >
        PRINCIPAL BANNER
      </div>

      {/* Secondary Banner 766 × 100 · 16px arriba de Categorías, centrado */}
      <div
        data-slot="secondary-banner"
        style={{
          position: "absolute", left: "50%", bottom: 700, transform: "translateX(-50%)",
          width: 766, height: 100, borderRadius: 8, background: "#E9EAEC",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
          fontSize: 13, fontWeight: 600, letterSpacing: "0.06em", color: "#9AA1AC",
        }}
      >
        SECONDARY BANNER
      </div>

      {/* Sección Categorías 766 × 184 · 16px arriba del Subastador, centrada */}
      <div style={{ position: "absolute", left: "50%", bottom: 500, transform: "translateX(-50%)" }}>
        <CategoriesSection />
      </div>

      {/* Sección Subastador 766 × 352 · 16px arriba del banner, centrada */}
      <div style={{ position: "absolute", left: "50%", bottom: 132, transform: "translateX(-50%)" }}>
        <AuctioneerSection />
      </div>

      {/* Banner 768 × 100 · a 32px del bottom, centrado horizontalmente */}
      <div
        data-slot="banner"
        style={{
          position: "absolute",
          left: "50%",
          bottom: 16,
          transform: "translateX(-50%)",
          width: 766,
          height: 100,
          borderRadius: 8,
          background: "#F2F4F3",
          border: "1px dashed #CBD5E1",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontFamily: "monospace",
          fontSize: 12,
          letterSpacing: "0.08em",
          color: "#94A3B8",
        }}
      >
        BANNER · 766 × 100
      </div>
    </div>
  );
}

/**
 * Dimensiones del bloque HomepageMobile — módulo plano sin "use client".
 */

export const HOMEPAGE_MOBILE_WIDTH = 420;
export const HOMEPAGE_MOBILE_HEIGHT = 1800;

/**
 * HomepageMobile — Bloque de Concorde (Voyager DS)
 *
 * Página de inicio · mobile (420 de ancho). Por ahora:
 *   · Header 420×64 (logo de la marca a la izquierda + «Ingresa»)
 *   · Banner 388×598 (placeholder, a 16px de margen)
 * Iremos montando las demás secciones encima.
 */

"use client";

import { useState } from "react";
import type { JSX } from "react";
import AppHeader from "../../header/desktop/Header";
import CardTitle from "../../../components/CardTitle";
import OfferType from "../../../components/OfferType";
import CategoryCard from "../../../components/CategoryCard";
import OfferCard from "../../../components/OfferCard";
import BadgeStatus from "../../../components/BadgeStatus";
import ProfileButton from "../../../components/ProfileButton";
import SidebarMobile, { SidebarMenuButton } from "../../sidebar/mobile/SidebarMobile";

import { HOMEPAGE_MOBILE_WIDTH, HOMEPAGE_MOBILE_HEIGHT } from "./dimensions";
export { HOMEPAGE_MOBILE_WIDTH, HOMEPAGE_MOBILE_HEIGHT } from "./dimensions";

// Card blanca de sección (388 de ancho, sombra estándar del homepage)
const SECTION_CARD = {
  width: 388,
  boxSizing: "border-box" as const,
  background: "#ffffff",
  borderRadius: 8,
  boxShadow: "rgba(0,0,0,0.1) 0px 0px 16px 4px",
  padding: 16,
};

// Overrides: OfferType llena su columna (2-up) y CategoryCard a 86 para que
// las 4 entren en la fila.
const HM_STYLES = `
.poftype.hm-oftype { width: 100%; box-sizing: border-box; }
.pcatcard.hm-cat { width: 86px; }
`;

export interface HomepageMobileProps {
  className?: string;
  /** Alto del marco para previsualizaciones (px). En producción se omite. Ver `SidebarMobile`. */
  frameHeight?: number;
}

export default function HomepageMobile({ className = "", frameHeight }: HomepageMobileProps): JSX.Element {
  const [menuOpen, setMenuOpen] = useState(false);

  const page = (
    <div
      className={className}
      data-block="homepage-mobile"
      style={{
        position: "relative",
        width: HOMEPAGE_MOBILE_WIDTH,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Header 420×64 · hamburguesa + logo de la marca a la izquierda */}
      <AppHeader
        width={HOMEPAGE_MOBILE_WIDTH}
        logo={
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <SidebarMenuButton onClick={() => setMenuOpen(true)} expanded={menuOpen} />
            <img src="/logo-preview.png" alt="VMC Subastas" style={{ height: 26, width: "auto", display: "block" }} />
          </div>
        }
      />

      <style suppressHydrationWarning dangerouslySetInnerHTML={{ __html: HM_STYLES }} />

      {/* Contenido a 16px de margen */}
      <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: 16 }}>
        {/* Banner · placeholder 388×598 */}
        <div
          data-slot="banner"
          style={{
            width: 388,
            height: 598,
            boxSizing: "border-box",
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          BANNER
        </div>

        {/* TIPO DE OFERTA · card 388×176 (CardTitle + 2 OfferType: EN VIVO / NEGOCIABLE) */}
        <div style={SECTION_CARD}>
          <CardTitle title="TIPO DE OFERTA" subtitle="" titleSize={14} />
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginTop: 20 }}>
            <OfferType variant="live" className="hm-oftype" />
            <OfferType variant="negotiable" className="hm-oftype" />
          </div>
        </div>

        {/* CATEGORÍAS · card 388×160 (CardTitle + 4 CategoryCard) */}
        <div style={SECTION_CARD}>
          <CardTitle title="CATEGORÍAS" subtitle="" titleSize={14} />
          <div style={{ display: "flex", justifyContent: "space-between", marginTop: 16 }}>
            <CategoryCard category="vehicular" className="hm-cat" />
            <CategoryCard category="maquinaria" className="hm-cat" />
            <CategoryCard category="equipos-diversos" className="hm-cat" />
            <CategoryCard category="articulos-diversos" className="hm-cat" />
          </div>
        </div>

        {/* SUBASTADOR · card 388×596 (SANTANDER CONSUMER + grid 2×2 de OfferCards) */}
        <div style={SECTION_CARD}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <CardTitle title="SANTANDER CONSUMER" subtitle="10 Ofertas" titleSize={16} subtitleSize={14} />
            <ProfileButton>Ir al Perfil</ProfileButton>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "170px 170px", justifyContent: "space-between", rowGap: 12, marginTop: 16 }}>
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" badge={<BadgeStatus variant="live" />} elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" badge={<BadgeStatus variant="proxima" />} elevated />
          </div>
        </div>

        {/* Secondary Banner · placeholder 388×116 */}
        <div
          data-slot="secondary-banner"
          style={{
            width: 388,
            height: 116,
            boxSizing: "border-box",
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          SECONDARY BANNER
        </div>
      </div>
    </div>
  );

  return (
    <SidebarMobile open={menuOpen} onOpenChange={setMenuOpen} frameHeight={frameHeight}>
      {page}
    </SidebarMobile>
  );
}

﻿"use client";

/**
 * OfferCard â€” Generado por Concorde
 * Fuente: https://voyager-ds.vercel.app/preview/components/button-primary
 * Generado: 2026-05-28
 * EDITAR LIBREMENTE despuÃ©s de generar
 *
 * Variantes: live (orange bar, pprice+price+like) Â·
 *            negotiable (teal bar, solo like)
 */

import { useState, useCallback, useId } from "react";
import type { JSX } from "react";

// â”€â”€â”€ Types â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

export type OfferCardVariant = "live" | "negotiable";

export interface OfferCardProps {
  /** Variante â€” determina barra inferior y fila de precio */
  variant: OfferCardVariant;
  /** TamaÃ±o. "short" = card compacta 134Ã—170 (solo imagen + tÃ­tulo/aÃ±o + barra,
   *  con el precio y el like como overlays sobre la imagen). Default "full". */
  size?: "full" | "short";
  /** Nombre del vehÃ­culo */
  name: string;
  /** AÃ±o */
  year: string | number;
  /**
   * Precio formateado ("US$ 9,999").
   * Si no se pasa, la fila de precio no se renderiza.
   * En negotiable solo aparece el like.
   */
  price?: string;
  /** URL imagen */
  imageSrc?: string;
  /** Alt text de imagen */
  imageAlt?: string;
  /** Badge de estado (pill BadgeStatus) â€” renderizado en img-badge slot */
  badge?: JSX.Element;
  /** Estado like controlado */
  liked?: boolean;
  /** Callback al alternar like */
  onLikeChange?: (liked: boolean) => void;
  /** Click en la card */
  onClick?: () => void;
  /** Aria label */
  "aria-label"?: string;
  /** Si false: showcase estático, sin hover/press. Default true */
  interactive?: boolean;
  /** Sombra elevada de Figma (X0 Y0 · Blur16 · Spread4 · #000000 10%). Default false */
  elevated?: boolean;
  className?: string;
}

// â”€â”€â”€ Self-contained CSS â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const STYLE_ID = "concorde-offercard-styles";

const OFFERCARD_STYLES = `
@keyframes offercard-heart-pop {
  0%   { transform: scale(1); }
  35%  { transform: scale(1.4); }
  65%  { transform: scale(0.85); }
  85%  { transform: scale(1.1); }
  100% { transform: scale(1); }
}
@keyframes offercard-pulse {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0.5; }
}

/* â”€â”€ Card base â€” ancho y alto fijo, igual en ambas variantes â”€â”€ */
.pcard {
  width: 170px;
  height: 232px;
  box-sizing: border-box;
  background: #ffffff;
  border-radius: 8px;
  box-shadow:
    rgba(0, 0, 0, 0.07) 0px 0px 16px 4px;
  display: flex;
  flex-direction: column;
  flex-shrink: 0;
  position: relative;
  overflow: hidden;
  transition:
    transform 150ms cubic-bezier(0.3, 0, 0, 1),
    box-shadow 150ms cubic-bezier(0.3, 0, 0, 1);
  cursor: pointer;
}

.pcard:hover:not(.pcard--disabled):not(.pcard--skeleton) {
  transform: translateY(-3px);
  box-shadow: oklch(0.22 0.18 285 / 0.12) 0px 12px 20px;
}

/* â”€â”€ Image â”€â”€ */
.pcard__img {
  width: 100%;
  height: 112px;
  background: oklch(0.93 0.006 220);
  flex-shrink: 0;
  overflow: hidden;
  border-radius: 8px 8px 0 0;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
}

.pcard__img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.pcard__img-badge {
  position: absolute;
  top: 8px;
  right: 8px;
  z-index: 2;
}

/* â”€â”€ Body â”€â”€ */
.pcard__body {
  display: flex;
  flex-direction: column;
  padding: 12px;
  height: 112px;
  flex-shrink: 0;
  box-sizing: border-box;
}

.pcard__meta {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.pcard__name {
  font-family: var(--vmc-font-display, 'Plus Jakarta Sans', sans-serif);
  font-size: 16px;
  font-weight: 700;
  line-height: 20px;
  color: #4c1ebc;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  margin: 0;
}

.pcard__year {
  font-family: var(--vmc-font-display, 'Plus Jakarta Sans', sans-serif);
  font-size: 11px;
  font-weight: 500;
  line-height: 16px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: #191c1c;
  margin: 0;
}

/* Price row â€” pprice + price text + like */
.pcard__price-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 10px;
  flex-shrink: 0;
}

.pcard__price-left {
  display: flex;
  align-items: center;
  gap: 6px;
}

.pcard__price-text {
  font-family: var(--vmc-font-mono, 'Roboto Mono', monospace);
  font-size: 13px;
  font-weight: 700;
  line-height: 20px;
  font-variant-numeric: tabular-nums;
  color: #4c1ebc;
  white-space: nowrap;
}

/* Like row â€” solo like (negotiable) */
.pcard__like-row {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  margin-top: 10px;
  flex-shrink: 0;
}

/* â”€â”€ Variants â€” bottom bars â”€â”€ */
.pcard--live {
  position: relative;
}
.pcard--live::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 8px;
  background: linear-gradient(90deg, #ff9639 0%, #ef852e 50%, #be3d00 100%);
