    </svg>
  );
}

// ── Separador primary / secondary ─────────────────────────────────────────────

export function SidebarSeparator(): JSX.Element {
  return <div className="sbi-sep" role="separator" aria-hidden="true" />;
}

// ── Componente principal ──────────────────────────────────────────────────────

export default function SidebarItem({
  id,
  icon,
  label,
  count,
  subitems,
  isActive = false,
  collapsed = false,
  onClick,
}: SidebarItemProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const [hovered, setHovered] = useState(false);
  const [activeSubId, setActiveSubId] = useState<string | undefined>();

  if (typeof document !== "undefined" && !_injected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _injected = true;
  }

  const iconState: "default" | "hover" | "active" =
    isActive ? "active" : hovered ? "hover" : "default";

  const cls = `sbi-item${isActive ? " sbi-item--active" : hovered ? " sbi-item--hover" : ""}${collapsed ? " sbi-item--collapsed" : ""}`;
  const hasSubitems = subitems && subitems.length > 0;
  const subitemsOpen = hasSubitems && isActive && !collapsed;

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div style={{ display: "flex", flexDirection: "column" }}>
        {/* Pill principal */}
        <div
          role="button"
          tabIndex={0}
          className={cls}
          onClick={() => onClick?.(id)}
          onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onClick?.(id); } }}
          onMouseEnter={() => setHovered(true)}
          onMouseLeave={() => setHovered(false)}
          aria-current={isActive ? "page" : undefined}
          aria-expanded={hasSubitems ? subitemsOpen : undefined}
          aria-label={count != null ? `${label}, ${count} subitems` : label}
          title={collapsed ? label : undefined}
        >
          {icon(iconState)}
          <div className="sbi-trailing">
            <span className="sbi-label">{label}</span>
            {count != null && <SidebarBadge count={count} active={isActive} uid={uid} />}
          </div>
        </div>

        {/* Subitems expandibles */}
        {hasSubitems && (
          <div className={`sbi-subitems${subitemsOpen ? " sbi-subitems--open" : ""}`}>
            {subitems.map((sub) => (
              <SidebarSubItem
                key={sub.id}
                {...sub}
                isActive={activeSubId === sub.id}
                onClick={(sid) => setActiveSubId(sid)}
              />
            ))}
          </div>
        )}
      </div>
    </>
  );
}

"use client";

/**
 * SidebarSubItem — subitem expandible 201×48 del SidebarItem
 * Fuente: Figma VOYAGER · "SideBarDefault" — State=Default/Hover/Active (subitems)
 *
 * El gradient border se hace con ::before + mask-composite:exclude porque
 * el fondo es rgba(255,255,255,0.06) — casi transparente. Con el truco
 * padding-box/border-box el gradiente se filtra a través del fondo.
 * La técnica de máscara dibuja el gradiente SOLO en el anillo del borde.
 */

import { useState } from "react";
import type { JSX } from "react";

export interface SidebarSubItemDef {
  id: string;
  label: string;
  count?: number;
}

interface SidebarSubItemProps extends SidebarSubItemDef {
  isActive?: boolean;
  onClick?: (id: string) => void;
}

const STYLE_ID = "concorde-sbsi-styles";
const STYLES = `
.sbsi-item {
  width: 100%;
  height: 48px;
  border-radius: 16px;
  display: flex;
  align-items: center;
  padding: 0 14px;
  box-sizing: border-box;
  cursor: pointer;
  user-select: none;
  outline: none;
  position: relative;
  background: rgba(255,255,255,0.10);
  transition: box-shadow 0.15s;
}
/* Hover — borde VYGradientOrange0 (::before) + drop #0A002E 60% (0,6,20,-4) */
.sbsi-item--hover {
  box-shadow: 0px 6px 20px -4px rgba(10,0,46,0.6);
}
/* Press/Active — borde VYStrokes1 (::before) + drop #0A002E 60% (0,12,36,-4) */
.sbsi-item--active {
  box-shadow: 0px 12px 36px -4px rgba(10,0,46,0.6);
}
/* Anillo de borde gradiente — solo visible en la franja del borde */
.sbsi-item--hover::before,
.sbsi-item--active::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 16px;
  pointer-events: none;
}
.sbsi-item--hover::before {
  padding: 1px;
  /* VYGradientOrange0 — dirección exacta del SVG (vector 94.42,127.15 → 143deg) */
  background: linear-gradient(143deg, #FF9639 0%, #EF852E 50%, #BE3D00 100%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  mask-composite: exclude;
}
.sbsi-item--active::before {
  padding: 1.5px;
  /* VYStrokes1 — dirección exacta del SVG (vector 94.42,127.15 → 143deg) */
  background: linear-gradient(143deg, #FFFFFF 0%, #F4AC59 22.1%, #8460E5 74.5%, #FFFFFF 100%);
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  mask-composite: exclude;
}
.sbsi-item:focus-visible {
  outline: 2px solid rgba(255,255,255,0.5);
  outline-offset: 2px;
}
.sbsi-label {
  flex: 1;
  font-size: 14px;
  font-weight: 600;
  letter-spacing: -0.01em;
  color: #D1D5DC;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
  position: relative;
  z-index: 1;
}
.sbsi-count {
  font-size: 12px;
  font-weight: 500;
  color: rgba(255,255,255,0.7);
  white-space: nowrap;
  flex-shrink: 0;
  position: relative;
  z-index: 1;
}
@media (prefers-reduced-motion: reduce) {
  .sbsi-item { transition: none; }
}
`;

let _injected = false;

export default function SidebarSubItem({
  id,
  label,
  count,
  isActive = false,
  onClick,
}: SidebarSubItemProps): JSX.Element {
  const [hovered, setHovered] = useState(false);
  const [pressed, setPressed] = useState(false);

  if (typeof document !== "undefined" && !_injected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _injected = true;
  }

  const showActive = isActive || pressed;
  const cls = `sbsi-item${showActive ? " sbsi-item--active" : hovered ? " sbsi-item--hover" : ""}`;

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div
        role="button"
        tabIndex={0}
        className={cls}
        onClick={() => onClick?.(id)}
        onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onClick?.(id); } }}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => { setHovered(false); setPressed(false); }}
        onMouseDown={() => setPressed(true)}
        onMouseUp={() => setPressed(false)}
        aria-current={isActive ? "page" : undefined}
      >
        <span className="sbsi-label">{label}</span>
        {count != null && <span className="sbsi-count">({count})</span>}
      </div>
    </>
  );
}

/**
 * Dimensiones del bloque SidebarMobile — módulo plano (sin "use client") para que
 * los Server Components puedan importarlas sin obtener `undefined`.
 */

/** Ancho del viewport móvil de referencia. */
export const SIDEBAR_MOBILE_WIDTH = 420;
/** Alto del viewport móvil de referencia. */
export const SIDEBAR_MOBILE_HEIGHT = 780;
/** Ancho del panel deslizante (igual que el Sidebar de escritorio). */
export const SIDEBAR_DRAWER_WIDTH = 226;

"use client";

/**
 * SidebarMobile — variante móvil del bloque Sidebar (Voyager DS).
 *
 * Reutiliza el mismo `Sidebar` de escritorio (idénticos colores, glass, gradientes
 * y estados) y lo presenta como un drawer: se desliza desde la izquierda por encima
 * del contenido y oscurece el fondo con un backdrop, en lugar de empujar el layout.
 *
 * @example
 * ```tsx
 * const [open, setOpen] = useState(false);
 * <SidebarMobile open={open} onOpenChange={setOpen}>
 *   {appContent}
 * </SidebarMobile>
 * ```
 *
 * El botón que abre el drawer se coloca en el header de la app y se cablea a
 * `onOpenChange(true)` (o usa `showTrigger` para el trigger flotante integrado).
 * Cierra con: backdrop, tecla Escape, o el botón del propio Sidebar.
 */

import { useEffect, useId, useRef, useState } from "react";
import type { JSX, ReactNode } from "react";
import Sidebar, { type SidebarNavItem } from "../desktop/Sidebar";
import { SIDEBAR_DRAWER_WIDTH } from "./dimensions";

export { SIDEBAR_MOBILE_WIDTH, SIDEBAR_MOBILE_HEIGHT, SIDEBAR_DRAWER_WIDTH } from "./dimensions";
export type { SidebarNavItem };

const EASE = "cubic-bezier(0.4,0,0.2,1)";

const STYLE_ID = "concorde-sidebar-mobile-styles";
const STYLES = `
.sbm-root { position: relative; }

/* Marco opcional para previews: alto fijo con scroll interno; su transform crea el
   containing block que ancla el drawer fixed dentro del marco (ver prop frameHeight). */
.sbm-frame {
  position: relative;
  height: 100%;
  overflow-y: auto;
  overflow-x: hidden;
  transform: translateZ(0);
  scrollbar-width: none;
  -ms-overflow-style: none;
}
.sbm-frame::-webkit-scrollbar { width: 0; height: 0; display: none; }
.sbm-frame--locked { overflow: hidden; }

.sbm-trigger {
  position: absolute;
  top: 16px;
  left: 16px;
  z-index: 7;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 44px;
  height: 44px;
  padding: 0;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 12px;
  background: #2E0F70;
  box-shadow: 0 6px 18px -6px rgba(10,0,46,0.6);
  cursor: pointer;
  transition: transform 0.15s, background 0.15s, opacity 0.2s;
}
.sbm-trigger:hover { background: #3a1a86; }
.sbm-trigger:active { transform: scale(0.94); }
.sbm-trigger:focus-visible { outline: 2px solid #8460E5; outline-offset: 2px; }

.sbm-backdrop {
  position: fixed;
  inset: 0;
  z-index: 40;
  background: rgba(10,0,38,0.55);
  -webkit-backdrop-filter: blur(2px);
  backdrop-filter: blur(2px);
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.28s ${EASE};
}
.sbm-backdrop--open { opacity: 1; pointer-events: auto; }

.sbm-panel {
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  z-index: 41;
  width: ${SIDEBAR_DRAWER_WIDTH}px;
  max-width: 86%;
  transform: translateX(-100%);
  transition: transform 0.3s ${EASE};
  box-shadow: 0 0 40px -4px rgba(10,0,46,0.6);
  will-change: transform;
}
.sbm-panel--open { transform: translateX(0); }
.sbm-panel-inner { height: 100%; }
.sbm-panel-inner > [data-slot="sidebar"] { height: 100% !important; }

@media (prefers-reduced-motion: reduce) {
  .sbm-trigger, .sbm-backdrop, .sbm-panel { transition: none; }
}
`;

let _injected = false;

export interface SidebarMobileProps {
  /** Contenido de la aplicación. Se renderiza detrás del drawer y se oscurece al abrir. */
  children?: ReactNode;
  /** Logo mostrado en la cabecera del Sidebar. */
  logo?: ReactNode;
  /** Ítems de navegación principales. Por defecto usa los del Sidebar. */
  primaryItems?: SidebarNavItem[];
  /** Ítems de navegación secundarios (bajo el separador). */
  secondaryItems?: SidebarNavItem[];
  /** Id del ítem activo inicial. */
  defaultActiveId?: string;
  /** Estado abierto (modo controlado). Si se omite, el drawer gestiona su estado. */
  open?: boolean;
  /** Se invoca al abrir o cerrar el drawer. */
  onOpenChange?: (open: boolean) => void;
  /** Se invoca con el id del ítem seleccionado. */
  onItemClick?: (id: string) => void;
  /** Se invoca al pulsar el CTA del banner inferior. */
  onBannerCta?: () => void;
  /**
   * Cierra el drawer al seleccionar un ítem. Por defecto `false`: seleccionar un
   * ítem solo expande sus subítems. Actívalo cuando los ítems naveguen a una ruta.
   */
  closeOnItemClick?: boolean;
  /**
   * Muestra un botón hamburguesa flotante que abre el drawer. Por defecto `false`:
   * lo habitual es colocar el botón en la cabecera de la app y llamar a
   * `onOpenChange(true)`.
   */
  showTrigger?: boolean;
  /**
   * Alto del bloque interno del Sidebar (cabecera + navegación + banner), en px.
   * Debe cubrir el alto visible para que el banner no se recorte. Por defecto `780`.
   */
  drawerContentHeight?: number;
  /**
   * Envuelve el contenido en un marco de alto fijo (px) con scroll interno,
   * confinando el drawer a ese marco. Pensado para previsualizaciones embebidas;
   * en producción se omite y el drawer flota sobre el viewport completo.
   */
  frameHeight?: number;
}

export default function SidebarMobile({
  children,
  logo,
  primaryItems,
  secondaryItems,
  defaultActiveId,
  open: openProp,
  onOpenChange,
  onItemClick,
  onBannerCta,
  closeOnItemClick = false,
  showTrigger = false,
  drawerContentHeight = 780,
  frameHeight,
}: SidebarMobileProps): JSX.Element {
  const rootRef = useRef<HTMLDivElement>(null);
  const [internalOpen, setInternalOpen] = useState(false);
  const open = openProp ?? internalOpen;

  function setOpen(next: boolean): void {
    if (openProp === undefined) setInternalOpen(next);
    onOpenChange?.(next);
  }

  if (typeof document !== "undefined" && !_injected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _injected = true;
  }

  useEffect(
    function closeOnEscape() {
      if (!open) return;
      function onKey(e: KeyboardEvent): void {
        if (e.key === "Escape") setOpen(false);
      }
      document.addEventListener("keydown", onKey);
      return () => document.removeEventListener("keydown", onKey);
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [open],
  );

  useEffect(
    function lockScroll() {
      if (!open || typeof document === "undefined") return;
      // Con frame, el scroll vive en el marco; sin frame, en el documento. En el
      // marco reseteamos scrollTop a 0 para que el drawer fixed cubra todo lo visible.
      const frame = frameHeight ? rootRef.current : null;
      const prevBodyOverflow = document.body.style.overflow;
      let prevScrollTop = 0;
      if (frame) {
        prevScrollTop = frame.scrollTop;
        frame.scrollTop = 0;
      } else {
        document.body.style.overflow = "hidden";
      }
      return () => {
        if (frame) frame.scrollTop = prevScrollTop;
        else document.body.style.overflow = prevBodyOverflow;
      };
    },
    [open, frameHeight],
  );

  function handleItemClick(id: string): void {
    onItemClick?.(id);
    if (closeOnItemClick) setOpen(false);
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div
        ref={rootRef}
        className={`sbm-root${frameHeight ? " sbm-frame" : ""}${frameHeight && open ? " sbm-frame--locked" : ""}`}
        style={frameHeight ? { height: frameHeight } : undefined}
      >
        {children}

        {showTrigger ? (
          <button
            type="button"
            className="sbm-trigger"
            onClick={() => setOpen(true)}
            aria-label="Abrir menú"
            aria-expanded={open}
            style={{ opacity: open ? 0 : 1, pointerEvents: open ? "none" : "auto" }}
          >
            <HamburgerIcon />
          </button>
        ) : null}

        <div
          className={`sbm-backdrop${open ? " sbm-backdrop--open" : ""}`}
          onClick={() => setOpen(false)}
          aria-hidden="true"
        />

        <div
          className={`sbm-panel${open ? " sbm-panel--open" : ""}`}
          role="dialog"
          aria-modal="true"
          aria-label="Navegación"
          aria-hidden={!open}
        >
          <div className="sbm-panel-inner">
            <Sidebar
              logo={logo}
              primaryItems={primaryItems}
              secondaryItems={secondaryItems}
              defaultActiveId={defaultActiveId}
              height="100%"
              contentHeight={drawerContentHeight}
              collapsed={false}
              onCollapsedChange={() => setOpen(false)}
              onItemClick={handleItemClick}
              onBannerCta={onBannerCta}
            />
          </div>
        </div>
      </div>
    </>
  );
}

const MENU_BTN_STYLE_ID = "concorde-sidebar-menu-button-styles";
const MENU_BTN_STYLES = `
.sbm-menu-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  padding: 0;
  border: none;
  border-radius: 10px;
  background: transparent;
  cursor: pointer;
  transition: background 0.15s, transform 0.15s;
}
.sbm-menu-btn:hover { background: rgba(255,255,255,0.10); }
.sbm-menu-btn:active { transform: scale(0.92); }
.sbm-menu-btn:focus-visible { outline: 2px solid #8460E5; outline-offset: 2px; }
`;

let _menuBtnInjected = false;

export interface SidebarMenuButtonProps {
  /** Se invoca al pulsar el botón (normalmente abre el drawer). */
  onClick: () => void;
  /** Estado abierto del drawer, para `aria-expanded`. */
  expanded?: boolean;
}

/**
 * Botón hamburguesa autocontenido para abrir el drawer desde la cabecera de la app.
 * Incluye el ícono, los estados (hover/active/focus) y la etiqueta accesible.
 */
export function SidebarMenuButton({ onClick, expanded = false }: SidebarMenuButtonProps): JSX.Element {
  if (typeof document !== "undefined" && !_menuBtnInjected) {
    if (!document.getElementById(MENU_BTN_STYLE_ID)) {
      const el = document.createElement("style");
      el.id = MENU_BTN_STYLE_ID;
      el.textContent = MENU_BTN_STYLES;
      document.head.appendChild(el);
    }
